    LITERLLMCreateTranscriptionRequest* create_transcription_request_handle = literllm_create_transcription_request_from_json("{\"file\":\"silence.mp3\",\"model\":\"whisper-1\"}");
    assert(create_transcription_request_handle != NULL && "failed to build request");
    const char* mock_base = getenv("MOCK_SERVER_URL");
    assert(mock_base != NULL && "MOCK_SERVER_URL must be set");
