    snprintf(base_url, sizeof(base_url), "%s/fixtures/edge_transcribe_empty_audio", mock_base);
    LITERLLMDefaultClient* client = literllm_create_client("test-key", base_url, (uint64_t)-1, (uint32_t)-1, NULL);
    assert(client != NULL && "failed to create client");
    LITERLLMTranscriptionResponse* result = literllm_default_client_transcribe(client, create_transcription_request_handle);
    assert(result != NULL && "expected call to succeed");
    char* text = literllm_transcription_response_text(result);
    assert(text != NULL && strstr(text, "") != NULL && "expected to contain substring");
